code = """import pandas as pd\nimport json\nimport re\n\n# Load funding data\nwith open(locals()[\'var_function-call-14481153673372787681\'], \'r\') as f:\n    funding_data = json.load(f)\nfunding_df = pd.DataFrame(funding_data)\n\n# Load civic documents data\nwith open(locals()[\'var_function-call-12785932103837883149\'], \'r\') as f:\n    civic_docs_data = json.load(f)\n\nextracted_projects_info = []\n\n# Keywords to identify relevant projects and their status\nemergency_keywords = [\'emergency\', \'fema\', \'disaster recovery\', \'caloes\', \'caljpia\', \'warning sirens\', \'fire recovery\', \'storm drain\', \'culvert repairs\', \'slope repairs\']\nstatus_mapping = {\n    \'design\': [\'design\', \'preliminary design\', \'in planning\', \'concept development\'],\n    \'completed\': [\'completed\', \'finished\', \'construction was completed\', \'notice of completion filed\'],\    \'not started\': [\'not started\', \'identified but not begun\', \'waiting for agreement\'],\n    \'under construction\': [\'under construction\', \'begin construction\', \'currently under construction\'],\n    \'delayed\': [\'delayed\']\n}\n\nfor doc in civic_docs_data:\n    text = doc[\'text\']\n    lines = text.split(\'\\n\')\n\n    for i, line in enumerate(lines):\n        line_lower = line.strip().lower()\n\n        # Check for presence of emergency/FEMA related keywords in the line\n        is_relevant_line = False\n        current_topics = []\n        for keyword in emergency_keywords:\n            if keyword in line_lower:\n                is_relevant_line = True\n                current_topics.append(keyword)\n\n        if is_relevant_line:\n            project_name_candidate = line.strip().replace(\'(cid:190)\', \'\').replace(\'(cid:131)\', \'\').strip()\n\n            # Filter out non-project lines that might contain keywords (e.g., headers, discussions)\n            if project_name_candidate and not any(phrase in project_name_candidate for phrase in [\'agenda item\', \'page\', \'to:\', \'prepared by:\', \'approved by:\', \'date prepared:\', \'meeting date:\', \'subject:\', \'recommended action:\', \'discussion:\']):\n                \n                # Try to get a more accurate project name by removing common suffixes/prefixes\n                project_name = re.sub(r\'\\s*\\\\((FEMA|CalOES|CalJPIA) Project\\\\)\', \'\', project_name_candidate, flags=re.IGNORECASE).strip()\n                if not project_name: # If after removing suffix, it\'s empty, use original candidate\n                    project_name = project_name_candidate\n\n                inferred_status = \'Unknown\'\n                # Look for status in the current line and the next few lines\n                search_window = 3 # Check current line and next 2 lines\n                context_lines = [lines[j].lower() for j in range(i, min(i + search_window, len(lines))) if j < len(lines)]\n                context_text = \' \'.join(context_lines)\n\n                for status_key, patterns in status_mapping.items():\n                    for pattern in patterns:\n                        if pattern in context_text:\n                            inferred_status = status_key\n                            break\n                    if inferred_status != \'Unknown\':\n                        break\n\n                # Add to extracted info if not already present to avoid duplicates from different documents\n                if not any(item[\'Project_Name\'] == project_name for item in extracted_projects_info):\n                    extracted_projects_info.append({\n                        \'Project_Name\': project_name,\n                        \'status\': inferred_status,\n                        \'topic\': \', \'.join(list(set(current_topics)))\n                    })\n\nprojects_df = pd.DataFrame(extracted_projects_info)\n\n# Merge funding data with project details\nmerged_df = pd.merge(funding_df, projects_df, on=\'Project_Name\', how=\'left\')\n\n# Fill NaN in \'topic\' and \'status\' columns with empty string or \'Unknown\' for robust string operations\nmerged_df[\'topic\'] = merged_df[\'topic\'].fillna(\'\')\nmerged_df[\'status\'] = merged_df[\'status\'].fillna(\'Unknown\')\n\n# Filter for projects related to \"emergency\" or \"FEMA\" based on Project_Name or topic\n# Re-filter in case some relevant projects were missed by the initial line-by-line check\nfiltered_df = merged_df[\n    merged_df[\'Project_Name\'].str.contains(\'FEMA|emergency|disaster|CalOES|CalJPIA|warning sirens|fire recovery|storm drain|culvert repairs|slope repairs\', case=False, na=False) |\n    merged_df[\'topic\'].str.contains(\'FEMA|emergency|disaster|CalOES|CalJPIA|warning sirens|fire recovery|storm drain|culvert repairs|slope repairs\', case=False, na=False)\n]\n\n# Select and rename columns for the final output\nfinal_result = filtered_df[[\'Project_Name\', \'Funding_Source\', \'Amount\', \'status\']].to_json(orient=\'records\')\n\nprint(\'__RESULT__:\')\nprint(final_result)\n"""

env_args = {'var_function-call-14481153673372787681': 'file_storage/function-call-14481153673372787681.json', 'var_function-call-12785932103837883149': 'file_storage/function-call-12785932103837883149.json'}

exec(code, env_args)
